import React from "react";

const VideoPanel = ({ children, height = "50vh" }) => {
  // La altura es una prop dinámica, por lo que la manejamos con un objeto de estilo.
  // Es la forma más limpia cuando el valor no es fijo.
  const panelStyle = {
    height: height,
  };

  return (
    <div
      style={panelStyle}
      // APLICACIÓN DE LA NUEVA PALETA MODERNA:
      // Bordes elegantes con gradientes y sombras sofisticadas
      className="w-full relative overflow-hidden border-t-[0.7vh] border-b-[0.7vh] border-gradient-to-r from-primary via-primary-light to-accent shadow-2xl rounded-2xl"
    >
      {/* Elementos decorativos modernos */}
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary via-primary-light to-accent"></div>
      <div className="absolute bottom-0 left-0 w-full h-1 bg-gradient-to-r from-accent via-primary-light to-primary"></div>
      
      {/* Overlay sutil para mayor profundidad */}
      <div className="absolute inset-0 bg-gradient-to-t from-black/10 via-transparent to-transparent pointer-events-none"></div>
      
      <div className="absolute inset-0 w-full h-full">
        {/* Clonamos el `children` para aplicarle clases en lugar de estilos en línea. */}
        {React.Children.map(children, (child) =>
          React.isValidElement(child)
            ? React.cloneElement(child, {
                // Estas clases aseguran que el video (o cualquier otro elemento)
                // llene el panel y se mantenga centrado con transiciones suaves.
                className: "w-full h-full object-cover object-center transition-all duration-500 hover:scale-105 hover:brightness-110",
              })
            : child
        )}
      </div>
    </div>
  );
};

export default VideoPanel;
